127→//        if (apiUpload) {
128→//            return;
129→//        }
130→        if (StrUtil.isBlank(secret)) {
131→            throw new BusinessException(ActionException.MAN_MACHINE_VERIFICATION_FAILED);
132→        }
133→        // When not logged in, perform human-machine verification
134→        int hash = HashUtil.javaDefaultHash(secret);
135→        // The client uploads continuously, and the incoming secret remains unchanged.
136→        // Therefore, the verification can be skipped within the validity period of
137→        // the cache after the verification is passed.
138→        String key = StrUtil.format(GENERAL_LOCKED, "anonymous:upload", hash);
139→        if (BooleanUtil.isTrue(redisTemplate.hasKey(key))) {
140→            return;
141→        }
142→        String nodeKey = StrUtil.format(GENERAL_LOCKED, "anonymous:upload", mapId);
143→        if (BooleanUtil.isTrue(redisTemplate.hasKey(nodeKey))) {
144→            return;
145→        }
146→        // The verification is passed, and the timing cache is generated
147→        redisTemplate.opsForValue().set(key, "", 2, TimeUnit.HOURS);
148→        redisTemplate.opsForValue().set(nodeKey, "", 2, TimeUnit.HOURS);
149→    }
