325→    public AssetUploadResult uploadFile(InputStream in, long fileSize, String contentType) {
326→        log.info("upload non space resource files");
327→        AssetUploadResult result = new AssetUploadResult();
328→
329→        try (InputStreamCache streamCache = new InputStreamCache(in, fileSize)) {
330→            String checksum = DigestUtil.md5Hex(streamCache.getInputStream());
331→            AssetEntity byCheckSumInternal = getByCheckSumInternal(checksum);
