337→                result.setWidth(byCheckSumInternal.getWidth());
338→                result.setId(byCheckSumInternal.getId());
339→                result.setSize(Long.valueOf(byCheckSumInternal.getFileSize()));
340→                return result;
341→            }
342→            result.setBucket(constProperties.getOssBucketByAsset().getType());
343→            // Upload public area
