375→    private String uploadAndSavePdfImg(final String bucketName,
376→                                       final String key) {
377→        AtomicReference<String> pdfImgUploadPath = new AtomicReference<>();
378→        ossTemplate.executeStreamFunction(bucketName, key,
379→                in -> {
380→                    InputStream imageIn = PdfToImageUtil.convert(in);
381→                    if (imageIn == null) {
382→                        return;
383→                    }
384→                    try (InputStreamCache pdfImgStreamCache =
385→                                 new InputStreamCache(imageIn,
386→                                         imageIn.available())) {
387→                        pdfImgUploadPath.set(
388→                                StringUtil.buildPath(COLLABSPACE_PREFIX));
389→                        String pdfImgChecksum =
390→                                DigestUtil.md5Hex(
391→                                        pdfImgStreamCache.getInputStream());
392→                        ossTemplate.upload(bucketName,
393→                                pdfImgStreamCache.getInputStream(),
394→                                pdfImgUploadPath.get(),
395→                                MediaType.IMAGE_JPEG_VALUE, pdfImgChecksum);
396→                    } catch (IOException e) {
397→                        log.error("Failed to upload PDF preview resource", e);
398→                    }
399→                });
400→        return pdfImgUploadPath.get();
401→    }
