403→    @Override
404→    @Transactional(rollbackFor = Throwable.class)
405→    public AssetUploadResult uploadFileInDeveloper(InputStream in, String uploadPath,
406→                                                   String fileOriginalName, long fileSize,
407→                                                   String contentType, Long createdBy,
408→                                                   DeveloperAssetType developerAssetType) {
409→        ExceptionUtil.isFalse(MediaType.TEXT_HTML_VALUE.equals(contentType),
410→            ActionException.FILE_NOT_SUPPORT_HTML);
411→        ExceptionUtil.isNotNull(createdBy, AuthException.UNAUTHORIZED);
412→
413→        AssetUploadResult result = new AssetUploadResult();
414→        try (InputStreamCache streamCache = new InputStreamCache(in, fileSize)) {
415→            // set file name
416→            result.setName(fileOriginalName);
417→            // set resource size
418→            result.setSize(fileSize);
419→            // md5 check to determine whether the file already exists
420→            String checksum = DigestUtil.md5Hex(streamCache.getInputStream());
421→            AssetEntity assetEntity = baseMapper.selectByChecksum(checksum);
422→            // read image
423→            ImageDto imageDto = getImageInfo(streamCache.getInputStream());
424→            if (imageDto != null) {
425→                result.setHeight(imageDto.getHeight());
426→                result.setWidth(imageDto.getWidth());
427→            }
428→            if (ObjectUtil.isNull(assetEntity)) {
429→                // does not exist, upload and store to the cloud
430→                if (StrUtil.isBlank(uploadPath)) {
431→                    // If not specified, use default name, specify suffix for
432→                    uploadPath = buildPath(DEVELOP_PREFIX);
433→                }
434→                // upload attachment
435→                ossTemplate.upload(constProperties.getOssBucketByAsset().getBucketName(),
436→                    streamCache.getInputStream(), uploadPath, contentType, checksum);
437→                // Calculate the file header Sum
438→                String headSum = DigestUtil.createHeadSum(streamCache.getInputStream());
439→                // Save into the database and bind the developer attachment table relationship
440→                Long assetId = this.save(checksum, headSum, fileSize, uploadPath, contentType,
441→                    result.getHeight(), result.getWidth(), result.getPreview());
442→                iDeveloperAssetService.saveAssetInDeveloper(assetId, createdBy, checksum,
443→                    developerAssetType, fileOriginalName, fileSize);
444→
445→                result.setToken(uploadPath);
446→                result.setBucket(constProperties.getOssBucketByAsset().getType());
447→            } else {
448→                // exist
449→                result.setToken(assetEntity.getFileUrl());
450→                result.setBucket(assetEntity.getBucket());
451→            }
452→        } catch (IOException e) {
453→            throw new RuntimeException("Failed to upload resource", e);
454→        }
455→        return result;
456→    }
