                .in(DocSubscriptionNotificationEntity::getId, notificationIds)
                .set(DocSubscriptionNotificationEntity::getIsRead, 1);
        baseMapper.update(null, wrapper);
        log.info("[DocSubscriptionNotification] markReadByIds userId={} ids={}", userId, notificationIds);
    }

    @Override
    public void markAllReadByUserId(Long userId) {
        UpdateWrapper<DocSubscriptionNotificationEntity> wrapper = new UpdateWrapper<>();
        wrapper.lambda()
                .eq(DocSubscriptionNotificationEntity::getUserId, userId)
                .eq(DocSubscriptionNotificationEntity::getIsRead, 0)
                .set(DocSubscriptionNotificationEntity::getIsRead, 1);
        baseMapper.update(null, wrapper);
        log.info("[DocSubscriptionNotification] markAllRead userId={}", userId);
    }
}

