package com.yottastudios.ns.collabspace.subscription.enums;

import com.fasterxml.jackson.annotation.JsonValue;
import lombok.AllArgsConstructor;
import lombok.Getter;

/**
 * IM 推送渠道枚举
 */
@Getter
@AllArgsConstructor
public enum ImChannelEnum {

    /** Knock 外网推送 */
    KNOCK("knock", "Knock (外网)"),

    /** Mattermost 内网推送 */
    MM("mm", "Mattermost (内网)"),

    /** 不推送 IM */
    NONE("none", "不推送IM");

    @JsonValue
    private final String value;

    private final String label;

    /**
     * 根据 value 获取枚举实例
     *
     * @param value 枚举值字符串
     * @return 对应枚举，未匹配时返回 {@link #NONE}
     */
    public static ImChannelEnum fromValue(String value) {
        for (ImChannelEnum channel : values()) {
            if (channel.value.equals(value)) {
                return channel;
            }
        }
        return NONE;
    }
}
